mapper.select:
SELECT tcm_herb_id as id, herb_name_zh as label
FROM core_tcm_herbs
WHERE tcm_herb_id = #{herbId} 
   OR herb_name_zh = #{herbId}
   OR pinyin_name = #{herbId}
LIMIT 1

SELECT tcm_prescription_id as id, name_zh as label
FROM tcm_prescriptions
WHERE tcm_prescription_id = #{prescriptionId}
   OR name_zh = #{prescriptionId}
   OR pinyin_name = #{prescriptionId}
LIMIT 1

SELECT tcm_tar_id as id, symbol as label
FROM targets
WHERE tcm_tar_id = #{geneId}
   OR symbol = #{geneId}
LIMIT 1

SELECT disease_id as id, disease_name as label
FROM diseases
WHERE disease_id = #{diseaseId}
   OR disease_name = #{diseaseId}
LIMIT 1

SELECT tcm_symptom_id as id, symptom_name_zh as label
FROM tcm_symptoms
WHERE tcm_symptom_id = #{symptomId}
   OR symptom_name_zh = #{symptomId}
   OR symptom_pinyin = #{symptomId}
LIMIT 1

SELECT tcm_syndrome_id as id, syndrome_name_zh as label
FROM tcm_syndromes
WHERE tcm_syndrome_id = #{syndromeId}
   OR syndrome_name_zh = #{syndromeId}
   OR syndrome_pinyin = #{syndromeId}
   OR syndrome_english = #{syndromeId}
LIMIT 1

SELECT wm_symptom_id as id, symptom_name as label
FROM wm_symptoms
WHERE wm_symptom_id = #{wmSymptomId}
   OR symptom_name = #{wmSymptomId}
LIMIT 1

SELECT tcm_herb_id as id, herb_name_zh as name, pinyin_name as pinyin
FROM core_tcm_herbs
WHERE herb_name_zh LIKE #{keyword} OR pinyin_name LIKE #{keyword}
ORDER BY herb_name_zh
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM core_tcm_herbs
WHERE herb_name_zh LIKE #{keyword} OR pinyin_name LIKE #{keyword}

SELECT tcm_prescription_id as id, name_zh as name, pinyin_name as pinyin
FROM tcm_prescriptions
WHERE name_zh LIKE #{keyword} OR pinyin_name LIKE #{keyword}
ORDER BY name_zh
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM tcm_prescriptions
WHERE name_zh LIKE #{keyword} OR pinyin_name LIKE #{keyword}

SELECT COUNT(*)
FROM tcm_compounds
WHERE inchikey LIKE #{keyword} OR molecular_formula LIKE #{keyword}

SELECT tcm_tar_id as id, symbol as name, description as extra
FROM targets
WHERE symbol LIKE #{keyword} OR description LIKE #{keyword}
ORDER BY symbol
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM targets
WHERE symbol LIKE #{keyword} OR description LIKE #{keyword}

SELECT disease_id as id, disease_name as name, source as extra
FROM diseases
WHERE disease_name LIKE #{keyword} OR disease_id LIKE #{keyword}
ORDER BY disease_name
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM diseases
WHERE disease_name LIKE #{keyword} OR disease_id LIKE #{keyword}

SELECT tcm_symptom_id as id, symptom_name_zh as name, symptom_pinyin as extra
FROM tcm_symptoms
WHERE symptom_name_zh LIKE #{keyword} OR symptom_pinyin LIKE #{keyword}
ORDER BY symptom_name_zh
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM tcm_symptoms
WHERE symptom_name_zh LIKE #{keyword} OR symptom_pinyin LIKE #{keyword}

SELECT tcm_syndrome_id as id, syndrome_name_zh as name, syndrome_pinyin as extra
FROM tcm_syndromes
WHERE syndrome_name_zh LIKE #{keyword} 
   OR syndrome_pinyin LIKE #{keyword}
   OR syndrome_english LIKE #{keyword}
ORDER BY syndrome_name_zh
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM tcm_syndromes
WHERE syndrome_name_zh LIKE #{keyword} 
   OR syndrome_pinyin LIKE #{keyword}
   OR syndrome_english LIKE #{keyword}

SELECT wm_symptom_id as id, symptom_name as name, umls_id as extra
FROM wm_symptoms
WHERE symptom_name LIKE #{keyword} OR wm_symptom_id LIKE #{keyword}
ORDER BY symptom_name
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM wm_symptoms
WHERE symptom_name LIKE #{keyword} OR wm_symptom_id LIKE #{keyword}
